mapper.insert:
INSERT INTO schedule (
title, description, category, region,
start_date, end_date, max_participants
) VALUES (
#{title}, #{description}, #{category}, #{region},
#{startDate}, #{endDate}, #{maxParticipants}
)

mapper.select:
SELECT * FROM schedule WHERE status = 'recruiting'
AND category = #{category}
AND region = #{region}
ORDER BY view_count DESC
ORDER BY created_at DESC

mapper.update:
UPDATE participation
SET status = #{status}
WHERE id = #{id}
